    13→/**
    14→ * Integration test for a large API specification generation. This test uses the nzcs1
    15→ * ontology.configuration file to generate the API spec and verifies specific aspects of the
    16→ * generated OpenAPI document. It focuses on features not covered by the SimpleApiIT test.
    17→ */
    18→public class LargeApiIT {
    19→
    20→  ReadContext apiSpec = TestUtil.getGeneratedSpec(
    21→      TestUtil.asFilePath(LargeApiIT.class, "config_nzcs1.yaml"));
    22→
    23→  @Test
    24→  public void testApiKeySecurityScheme() {
    25→    // Verify that the security schemes are correctly defined
    26→    Map<String, Object> securitySchemes = apiSpec.read("$.components.securitySchemes");
    27→    assertNotNull(securitySchemes, "Security schemes should be defined");
    28→
    29→    // Check for specific security scheme
    30→    assertTrue(securitySchemes.containsKey("apiKeyAuth"), "ApiKeyAuth scheme should be present");
    31→    Map<String, Object> apiKeyAuth = (Map<String, Object>) securitySchemes.get("apiKeyAuth");
    32→    assertEquals("apiKey", apiKeyAuth.get("type"), "ApiKeyAuth type should be 'apiKey'");
    33→    assertEquals("header", apiKeyAuth.get("in"), "ApiKeyAuth should be in 'header'");
    34→    assertEquals("X-Api-Key", apiKeyAuth.get("name"), "ApiKeyAuth name should be 'X-Api-Key'");
    35→
    36→    assertEquals(1, apiSpec.read("$.security[?(@.apiKey)]", List.class).size(),
    37→        "There should be one global security requirement for oauth2");
    38→  }
    39→
    40→  @Test
    41→  public void testOauthSecurityScheme() {
    42→    // Verify that the security schemes are correctly defined
    43→    Map<String, Object> securitySchemes = apiSpec.read("$.components.securitySchemes");
    44→    assertNotNull(securitySchemes, "Security schemes should be defined");
    45→
    46→    // Check for specific security scheme
    47→    assertTrue(securitySchemes.containsKey("oauth2"), "OAuth2 scheme should be present");
    48→    Map<String, Object> oauth2 = (Map<String, Object>) securitySchemes.get("oauth2");
    49→    assertEquals("oauth2", oauth2.get("type"), "OAuth2 type should be 'oauth2'");
    50→    Map<String, Object> flows = (Map<String, Object>) oauth2.get("flows");
    51→    assertNotNull(flows.get("authorizationCode"), "Authorization code flow should be present");
    52→
    53→    assertEquals(1, apiSpec.read("$.security[?(@.oauth2)]", List.class).size(),
    54→        "There should be one global security requirement for oauth2");
    55→  }
