    59→    assertEquals("read:nzcs1:Person",
    60→        apiSpec.read("$.paths['/Person/{PersonId}'].get.security[1].oauth2[0]"),
    61→        "GET /Person/{Person_ID} should require update:nzcs1:Person scope");
    62→    assertEquals("update:nzcs1:Person",
    63→        apiSpec.read("$.paths['/Person/{PersonId}'].put.security[1].oauth2[0]"),
    64→        "PUT /Person/{Person_ID} should require update:nzcs1:Person scope");
    65→    assertEquals("update:nzcs1:Person",
    66→        apiSpec.read("$.paths['/Person/{PersonId}'].patch.security[1].oauth2[0]"),
    67→        "PATCH /Person/{Person_ID} should require update:nzcs1:Person scope");
    68→    assertEquals("delete:nzcs1:Person",
    69→        apiSpec.read("$.paths['/Person/{PersonId}'].delete.security[1].oauth2[0]"),
    70→        "DELETE /Person/{Person_ID} should require delete:nzcs1:Person scope");
    71→    assertEquals("create:nzcs1:Person",
    72→        apiSpec.read("$.paths['/Person'].post.security[1].oauth2[0]"),
    73→        "POST /Person/{Person_ID} should require create:nzcs1:Person scope");
    74→    assertEquals("read:nzcs1:Person",
    75→        apiSpec.read("$.paths['/Person'].get.security[1].oauth2[0]"),
    76→        "POST /Person/{Person_ID} should require read:nzcs1:Person scope");
    77→
    78→  }
