   366→  private void setBooleanCombinationObjectProperties(OWLClassExpression expression,
   367→      Set<OWLClassExpression> ranges,
   368→      Set<OWLObjectProperty> properties) {
   369→    if (propertyName.isEmpty()) {
   370→      for (OWLObjectProperty property : properties) {
   371→        propertyName = cleanName(nameResolver.resolve(property));
   372→        objectPropertyNames.add(propertyName);
   373→        for (OWLClassExpression range : ranges) {
   374→          for (OWLObjectProperty rangeProp : range.getObjectPropertiesInSignature()) {
   375→            if (nameResolver.resolve(rangeProp).equals(propertyName)) {
   376→              range.accept(this);
   377→            }
   378→          }
   379→        }
   380→      }
   381→
   382→      for (OWLDataProperty property : expression.getDataPropertiesInSignature()) {
   383→        propertyName = cleanName(nameResolver.resolve(property));
   384→        dataPropertyNames.add(propertyName);
   385→        for (OWLClassExpression range : ranges) {
   386→          for (OWLDataProperty rangeProp : range.getDataPropertiesInSignature()) {
   387→            if (nameResolver.resolve(rangeProp).equals(propertyName)) {
   388→              range.accept(this);
   389→            }
   390→          }
   391→        }
   392→      }
   393→    } else {
   394→      for (OWLClassExpression range : ranges) {
   395→        Set<OWLClass> rangeClasses = range.getClassesInSignature();
   396→        if (rangeClasses.size() != 1) {
   397→          range.accept(this);
   398→        } else if (!range.asOWLClass().equals(owlThing)) {
   399→          // Range is tracked in objectPropertyRanges via visitor methods
   400→        } else {
   401→          logger.fine("Ignoring owl:Thing range " + propertyName);
   402→        }
   403→      }
   404→    }
