    25→public class OntologyUtil {
    26→
    27→  private static final PropertyNameResolver nameResolver = new PropertyNameResolver();
    28→  public static final List<IRI> DESCRIPTION_PROPERTIES = new ArrayList<>(Arrays.asList(IRI.create("",
    29→      OntologyConstants.apiDescription), OntologyConstants.SKOS_DEFINITION, OntologyConstants.RDFS_COMMENT,
    30→      OntologyConstants.PROV_DEFINITION
    31→
    32→  ));
    33→
    34→  /**
    35→   * Method that given a class, property or data property, searches for the best description.
    36→   *
    37→   * @param entity   entity to search.
    38→   * @param ontology ontology to be used to search descriptions.
    39→   * @return Description String (prioritizes English language)
    40→   */
    41→  public static String getDescription(OWLEntity entity, OWLOntology ontology) {
    42→    final String noDescriptionValue = "Description not available";
    43→    return DESCRIPTION_PROPERTIES.stream().flatMap(description -> EntitySearcher.getAnnotationObjects(entity, ontology)
    44→            .filter(WithIRI.onPropertyOf(description.getShortForm())))
    45→        .map(owlAnnotation -> owlAnnotation.getValue().asLiteral()).flatMap(Optional::stream)
    46→        .min(Comparator.comparingInt(owlLiteral -> owlLiteral.getLang().equals("en") ? 0 : 1))
    47→        .map(OWLLiteral::getLiteral).orElse(noDescriptionValue);
    48→  }
    49→
    50→  /**
    51→   * Given a stream of annotations collect the literal-valued ones with non-blank string values into a MultiMap keyed
    52→   * by annotation short iri
    53→   *
    54→   * @param annotations to process
    55→   * @return valid annotations
    56→   */
    57→  private static SetMultimap<String, String> collectStringAnnotations(Stream<OWLAnnotation> annotations) {
    58→    return annotations.collect(TreeMultimap::create, (map, annotation) -> annotation.getValue().asLiteral()
    59→        .map(OWLLiteral::getLiteral).filter(StringUtils::isNotBlank)
    60→            .ifPresent((value) -> map.put(nameResolver.resolve(annotation.getProperty()), value)),
    61→        SetMultimap::putAll);
    62→
    63→  }
    64→
    65→  /**
    66→   * @param annotated {@link HasAnnotations }
    67→   * @return MultiMap keyed by annotation short iri
    68→   * @see HasAnnotations
    69→   */
    70→  public static SetMultimap<String, String> annotationsOf(HasAnnotations annotated) {
    71→    return collectStringAnnotations(annotated.annotations());
    72→  }
    73→
    74→  /**
    75→   *
    76→   * @param owlEntity {@link EntitySearcher#getAnnotations(OWLEntity, OWLOntology)}
    77→   * @param ontology ontology to search
    78→   * @return MultiMap keyed by annotation short iri
    79→   */
    80→  public static SetMultimap<String, String> annotationsOf(OWLEntity owlEntity, OWLOntology ontology) {
    81→    return collectStringAnnotations(EntitySearcher.getAnnotations(owlEntity, ontology));
    82→  }
    83→
    84→  /**
    85→   * Get the first annotation of the lists of annotations by key (in future maybe prefer the english translation or
    86→   * some heuristic)
    87→   *
    88→   * @param owlEntity {@link EntitySearcher#getAnnotations(OWLEntity, OWLOntology)}
    89→   * @param ontology ontology to search
    90→   * @return Map keyed by annotation short iri
    91→   */
    92→  public static Map<String, String> defaultAnnotationsOf(OWLEntity owlEntity, OWLOntology ontology) {
    93→    return annotationsOf(owlEntity, ontology).entries().stream()
    94→        .collect(HashMap::new, (map, entry) -> map.putIfAbsent(entry.getKey(), entry.getValue()), HashMap::putAll);
    95→  }
    96→
    97→  /**
    98→   * Method that given a class, property or data property, searches for the best title. If no annotation title is
    99→   * found, it
   100→   * returns the short form of the IRI split on any case/word boundaries then title cased
   101→   *
   102→   * @param entity   class to search.
   103→   * @param ontology ontology to be used to search titles.
   104→   * @return Title String (prioritizes English language)
   105→   */
   106→  public static String getTitle(OWLEntity entity, OWLOntology ontology) {
   107→    final Map<String, String> annotations = defaultAnnotationsOf(entity, ontology);
   108→    return WordUtils.capitalize(Stream.of(OntologyConstants.apiDisplayLabel,
   109→            OntologyConstants.SKOS_PREFLABEL.getShortForm())
   110→        .filter(annotations::containsKey).findFirst().map(annotations::get)
   111→        .orElseGet(() -> nameResolver.resolve(entity).replaceAll("([a-z])([^a-z])", "$1 $2")));
   112→
   113→  }
   114→
   115→}
