    44→/**
    45→ * Maps an OWL class to an OpenAPI Schema object.
    46→ *
    47→ * <p>This mapper analyzes an OWL class from the ontology and generates a corresponding
    48→ * OpenAPI 3.1 ObjectSchema with properties derived from:
    49→ * <ul>
    50→ *   <li><b>Data properties</b> - mapped to primitive schema types (string, integer, etc.)</li>
    51→ *   <li><b>Object properties</b> - mapped to $ref references or inline schemas</li>
    52→ *   <li><b>Taxonomy properties</b> - mapped to enum schemas based on named individuals</li>
    53→ * </ul>
    54→ *
    55→ * <h2>Processing Pipeline</h2>
    56→ * <pre>
    57→ * OWLClass → SchemaVisitors → Axiom Collection → Restriction Merging
    58→ *                                    ↓
    59→ *         ┌────────────────────────────────────────────┐
    60→ *         │                                            │
    61→ *         ▼                    ▼                       ▼
    62→ *   DataPropertyMapper   ObjectPropertyMapper   TaxonomyPropertyMapper
    63→ *         │                    │                       │
    64→ *         └────────────────────┴───────────────────────┘
    65→ *                              ↓
    66→ *                      OpenAPI ObjectSchema
    67→ * </pre>
    68→ *
    69→ * <h2>Annotation Filtering</h2>
    70→ * <p>Only axioms annotated with {@code apiLabel} matching the schema label from
    71→ * {@link MappingContext#getSchemaLabel()} are included in the generated schema.
    72→ *
    73→ * <h2>Thread Safety</h2>
    74→ * <p>This class is <b>not thread-safe</b>. Each instance should be used to map
    75→ * a single OWL class and then discarded.
    76→ *
    77→ * @see DataPropertyMapper
    78→ * @see ObjectPropertyMapper
    79→ * @see TaxonomyPropertyMapper
    80→ * @see SchemaVisitor
    81→ */
    82→public class ResourceSchemaMapper {
    83→
    84→  /**
    85→   * Holds paired SchemaVisitors for analyzing object and data property restrictions.
    86→   *
    87→   * @param objectPropertyVisitor visitor that collects object property restrictions
    88→   * @param dataPropertyVisitor visitor that collects data property restrictions
    89→   */
    90→  private record VisitorPair(SchemaVisitor objectPropertyVisitor, SchemaVisitor dataPropertyVisitor) {}
    91→
    92→  /**
    93→   * Holds categorized axiom collections for the analyzed class.
    94→   *
    95→   * @param taxonomy axioms referencing named individuals (enum values)
    96→   * @param subClass direct SubClassOf axioms for the analyzed class
    97→   * @param superClass inherited axioms from the class hierarchy
    98→   */
    99→  private record AxiomCollection(
   100→      List<OWLSubClassOfAxiom> taxonomy,
   101→      List<OWLSubClassOfAxiom> subClass,
   102→      List<OWLSubClassOfAxiom> superClass) {}
   103→  private static final Logger logger = Logger.getLogger(ResourceSchemaMapper.class.getName());
   104→  private final MappingContext context;
   105→  private final PropertyNameResolver nameResolver = new PropertyNameResolver();
   106→  private final String type;
   107→  private final OWLClass cls;
   108→  private final String classDescription;
   109→  private final String name;
   110→  private final Schema<?> schema;
   111→
   112→  public Schema<?> getSchema() {
   113→    return schema;
   114→  }
   115→
   116→  public String getName() {
   117→    return name;
   118→  }
   119→
   120→  public ResourceSchemaMapper(MappingContext context, OWLClass cls, String clsDescription) {
   121→    this.context = context;
   122→    this.cls = cls;
   123→    this.classDescription = clsDescription;
   124→    this.type = "object";
   125→    this.name = nameResolver.resolve(cls);
   126→    this.schema = createSchema(cls);
   127→  }
   128→
   129→  /**
   130→   * Creates the OpenAPI schema for the analyzed OWL class.
   131→   *
   132→   * <p>This method orchestrates the schema generation by:
   133→   * <ol>
   134→   *   <li>Initializing the base ObjectSchema with metadata</li>
   135→   *   <li>Creating visitors to traverse class restrictions</li>
   136→   *   <li>Collecting relevant axioms from the ontology</li>
   137→   *   <li>Visiting axioms to gather property restrictions</li>
   138→   *   <li>Processing data, object, and taxonomy properties</li>
   139→   * </ol>
   140→   *
   141→   * @param analyzedClass the OWL class to generate a schema for
   142→   * @return the generated OpenAPI Schema object
   143→   */
   144→  private Schema<?> createSchema(OWLClass analyzedClass) {
   145→    Schema<?> schema = initializeResourceSchema();
   146→
   147→    VisitorPair visitors = createSchemaVisitors(analyzedClass);
   148→    AxiomCollection axioms = collectRelevantAxioms(analyzedClass);
   149→
   150→    visitAxiomsWithVisitors(visitors, axioms);
   151→
   152→    Map<String, Set<RestrictionInfo>> restrictions = mergeVisitorRestrictions(visitors);
   153→
   154→    processDataProperties(schema, visitors.dataPropertyVisitor(), restrictions, axioms.subClass());
   155→    processObjectProperties(schema, visitors.objectPropertyVisitor(), restrictions);
   156→    processTaxonomyProperties(schema, axioms.taxonomy());
   157→
   158→    if (schema.getProperties() == null || schema.getProperties().isEmpty()) {
   159→      logMissingPropertiesWarning(analyzedClass, axioms);
   160→    }
   161→
   162→    return schema;
   163→  }
   164→
   165→  /**
   166→   * Creates and configures the base ObjectSchema with standard properties.
   167→   *
   168→   * @return a new ObjectSchema configured with name, type, description, and OpenAPI 3.1 spec version
   169→   */
   170→  private Schema<?> initializeResourceSchema() {
   171→    Schema<?> resourceSchema = new ObjectSchema();
   172→    resourceSchema.setSpecVersion(SpecVersion.V31);
   173→    resourceSchema.setName(this.name);
   174→    resourceSchema.setDescription(this.classDescription);
   175→    resourceSchema.setType(this.type);
   176→    resourceSchema.setAdditionalProperties(false);
   177→    resourceSchema.setTitle(getLabel(this.cls));
   178→    return resourceSchema;
   179→  }
   180→
   181→  /**
   182→   * Creates paired SchemaVisitors for analyzing object and data property restrictions.
   183→   *
   184→   * <p>Both visitors traverse the same class hierarchy but collect different types
   185→   * of restrictions:
   186→   * <ul>
   187→   *   <li>Object visitor: collects SomeValuesFrom, AllValuesFrom, cardinality on object properties</li>
   188→   *   <li>Data visitor: collects DataSomeValuesFrom, DataAllValuesFrom, cardinality on data properties</li>
   189→   * </ul>
   190→   *
   191→   * @param analyzedClass the OWL class to analyze
   192→   * @return a record containing both configured visitors
   193→   */
   194→  private VisitorPair createSchemaVisitors(OWLClass analyzedClass) {
   195→    OWLDataFactory dataFactory = context.getManager().getOWLDataFactory();
   196→    OWLClass owlThing = dataFactory.getOWLThing();
   197→    return new VisitorPair(
   198→        new SchemaVisitor(analyzedClass, context.getOntology(), owlThing, "", false),
   199→        new SchemaVisitor(analyzedClass, context.getOntology(), owlThing, "", false));
   200→  }
   201→
   202→  /**
   203→   * Collects all relevant axioms for the analyzed class from the ontology.
   204→   *
   205→   * <p>Gathers three categories of axioms:
   206→   * <ul>
   207→   *   <li><b>Taxonomy axioms</b>: SubClassOf axioms referencing named individuals (enum values)</li>
   208→   *   <li><b>SubClass axioms</b>: Direct SubClassOf axioms for the analyzed class</li>
   209→   *   <li><b>SuperClass axioms</b>: Inherited axioms from the class hierarchy</li>
   210→   * </ul>
   211→   *
   212→   * @param analyzedClass the OWL class to collect axioms for
   213→   * @return a record containing categorized axiom lists
   214→   */
   215→  private AxiomCollection collectRelevantAxioms(OWLClass analyzedClass) {
   216→    OWLOntology ontology = context.getOntology();
   217→    return new AxiomCollection(
   218→        getTaxonomyAxioms(analyzedClass),
   219→        ontology.subClassAxiomsForSubClass(analyzedClass).toList(),
   220→        getSuperClassAxioms(analyzedClass, null).toList());
   221→  }
   222→
   223→  /**
   224→   * Visits axioms with the appropriate schema visitors to collect restrictions.
   225→   *
   226→   * <p>For each axiom, the superclass expression is visited by the object property
   227→   * visitor if it contains object properties, and by the data property visitor if
   228→   * it contains data properties.
   229→   *
   230→   * @param visitors the visitor pair to use
   231→   * @param axioms the axiom collection to process
   232→   */
   233→  private void visitAxiomsWithVisitors(VisitorPair visitors, AxiomCollection axioms) {
   234→    String schemaLabel = context.getSchemaLabel();
   235→
   236→    // Filter axioms to only those annotated with the target apiLabel
   237→    // This allows multiple API schemas to be generated from the same ontology
   238→    axioms.subClass().stream()
   239→        .filter(axiom -> !axioms.taxonomy().contains(axiom))
   240→        .filter(WithAnnotation.of(OntologyConstants.apiLabel, schemaLabel))
   241→        .map(OWLSubClassOfAxiom::getSuperClass)
   242→        .forEach(superClass -> visitSuperClass(superClass, visitors));
   243→
   244→    axioms.superClass().stream()
   245→        .map(OWLSubClassOfAxiom::getSuperClass)
   246→        .forEach(superClass -> visitSuperClass(superClass, visitors));
   247→  }
   248→
   249→  /**
   250→   * Visits a superclass expression with the appropriate visitors based on property types.
   251→   *
   252→   * @param superClass the class expression to visit
   253→   * @param visitors the visitor pair
   254→   */
   255→  private void visitSuperClass(OWLClassExpression superClass, VisitorPair visitors) {
   256→    if (!superClass.getObjectPropertiesInSignature().isEmpty()) {
   257→      superClass.accept(visitors.objectPropertyVisitor());
   258→    }
   259→    if (!superClass.getDataPropertiesInSignature().isEmpty()) {
   260→      superClass.accept(visitors.dataPropertyVisitor());
   261→    }
   262→  }
   263→
   264→  /**
   265→   * Merges typed restrictions from both schema visitors into a unified map.
   266→   *
   267→   * <p>Combines restrictions keyed by property name. A single property may have
   268→   * multiple restrictions (e.g., both minCardinality and maxCardinality).
   269→   *
   270→   * @param visitors the visitor pair containing collected restrictions
   271→   * @return map of property name → set of RestrictionInfo for that property
   272→   */
   273→  private Map<String, Set<RestrictionInfo>> mergeVisitorRestrictions(VisitorPair visitors) {
   274→    Map<String, Set<RestrictionInfo>> restrictions = new HashMap<>();
   275→    Stream.of(visitors.objectPropertyVisitor(), visitors.dataPropertyVisitor())
   276→        .map(SchemaVisitor::getRestrictions)
   277→        .flatMap(map -> map.entrySet().stream())
   278→        .forEach(entry -> restrictions.computeIfAbsent(entry.getKey(), k -> new LinkedHashSet<>())
   279→            .addAll(entry.getValue()));
   280→    return restrictions;
   281→  }
   282→
   283→  /**
   284→   * Finds a data property in the ontology by its resolved name.
   285→   *
   286→   * @param propertyName the short-form property name (e.g., "firstName")
   287→   * @return the matching OWLDataProperty, or empty if not found
   288→   */
   289→  private Optional<OWLDataProperty> findDataProperty(String propertyName) {
   290→    return context.getOntology()
   291→        .getDataPropertiesInSignature().stream()
   292→        .filter(prop -> nameResolver.resolve(prop).equals(propertyName))
   293→        .findFirst();
   294→  }
   295→
   296→  /**
   297→   * Finds an object property in the ontology by its resolved name.
   298→   *
   299→   * @param propertyName the short-form property name (e.g., "hasAddress")
   300→   * @return the matching OWLObjectProperty, or empty if not found
   301→   */
   302→  private Optional<OWLObjectProperty> findObjectProperty(String propertyName) {
   303→    return context.getOntology()
   304→        .getObjectPropertiesInSignature().stream()
   305→        .filter(prop -> nameResolver.resolve(prop).equals(propertyName))
   306→        .findFirst();
   307→  }
   308→
   309→  /**
   310→   * Extracts range type/class names for a property from multiple sources.
   311→   *
   312→   * <p>Ranges are collected from:
   313→   * <ol>
   314→   *   <li>The SchemaVisitor's property range multimap (from restriction fillers)</li>
   315→   *   <li>The RestrictionInfo objects themselves (via getRangeNames)</li>
   316→   * </ol>
   317→   *
   318→   * @param propertyName the property to extract ranges for
   319→   * @param rangesFromVisitor multimap of property → range classes/datatypes from visitor
   320→   * @param restrictions map of property → RestrictionInfo set
   321→   * @return deduplicated list of range type names
   322→   */
   323→  private List<String> extractPropertyRanges(
   324→      String propertyName,
   325→      Multimap<String, ? extends OWLEntity> rangesFromVisitor,
   326→      Map<String, Set<RestrictionInfo>> restrictions) {
   327→    List<String> ranges = new ArrayList<>();
   328→
   329→    // Extract from visitor's range multimap
   330→    rangesFromVisitor.get(propertyName).stream()
   331→        .map(nameResolver::resolve)
   332→        .forEach(ranges::add);
   333→
   334→    // Also extract from restrictions themselves
   335→    Set<RestrictionInfo> propertyRestrictions = restrictions.getOrDefault(propertyName, Set.of());
   336→    propertyRestrictions.stream()
   337→        .flatMap(r -> r.getRangeNames(nameResolver).stream())
   338→        .forEach(ranges::add);
   339→
   340→    // Remove duplicates to avoid treating single-range properties as multi-range
   341→    return ranges.stream().distinct().toList();
   342→  }
   343→
   344→  /**
   345→   * Extracts the example value for a data property from annotations.
   346→   *
   347→   * <p>Looks for skos:example annotations in two places (in order):
   348→   * <ol>
   349→   *   <li>On the SubClassOf axiom containing the property restriction</li>
   350→   *   <li>On the data property itself (as a default)</li>
   351→   * </ol>
   352→   *
   353→   * @param dataProperty the data property to find an example for
   354→   * @param subClassAxioms axioms that may contain restriction-level annotations
   355→   * @return the example value string, or null if none found
   356→   */
   357→  private String extractExampleValue(OWLDataProperty dataProperty, List<OWLSubClassOfAxiom> subClassAxioms) {
   358→    // First, look for a skos:example annotation on the restriction axiom itself
   359→    return subClassAxioms.stream()
   360→        .filter(axiom ->
   361→            axiom.getSuperClass() instanceof OWLDataRestriction restriction
   362→                && restriction.getProperty().asOWLDataProperty().getIRI().equals(dataProperty.getIRI()))
   363→        .map(axiom -> axiom.getAnnotations().stream()
   364→            .filter(annotation -> annotation.getProperty().getIRI().equals(OntologyConstants.SKOS_EXAMPLE))
   365→            .findFirst()
   366→            .flatMap(annotation -> annotation.mapLiteral(OWLLiteral::getLiteral)))
   367→        .flatMap(Optional::stream)
   368→        .findFirst()
   369→        // Fall back to the annotation on the data property itself
   370→        .orElse(OntologyUtil.defaultAnnotationsOf(dataProperty, context.getOntology())
   371→            .getOrDefault(OntologyConstants.SKOS_EXAMPLE.getShortForm(), null));
   372→  }
