   576→  /**
   577→   * Logs a warning when no properties were found for a class.
   578→   *
   579→   * <p>This typically indicates that the ontology is missing apiLabel annotations
   580→   * on the property restrictions, or that the schema label doesn't match.
   581→   *
   582→   * @param analyzedClass the class that had no mappable properties
   583→   * @param axioms all collected axioms (for diagnostic output)
   584→   */
   585→  private void logMissingPropertiesWarning(OWLClass analyzedClass, AxiomCollection axioms) {
   586→    logger.warning("No properties with " + OntologyConstants.apiLabel
   587→        + " annotation found for: " + analyzedClass);
   588→
   589→    List<OWLSubClassOfAxiom> allAxioms = Stream.of(axioms.superClass(), axioms.subClass(), axioms.taxonomy())
   590→        .flatMap(Collection::stream)
   591→        .toList();
   592→
   593→    if (!allAxioms.isEmpty()) {
   594→      allAxioms.stream()
   595→          .map(axiom -> axiom.getSuperClass().toString())
   596→          .forEach(s -> logger.warning("\tPossible property: " + s));
   597→    }
   598→  }
   599→
   600→  private List<OWLSubClassOfAxiom> getTaxonomyAxioms(OWLClass analyzedClass) {
   601→    Set<OWLSubClassOfAxiom> subAx = context.getOntology().getSubClassAxiomsForSubClass(analyzedClass);
   602→    String schemaAnnotation = getSchemaAnnotation(context.getSchemaLabel());
   603→
   604→    return subAx.stream().filter(ax -> ax.annotations()
   605→        .anyMatch(annotation -> annotation.getValue().toString().equals(schemaAnnotation))).filter(ax -> {
   606→      OWLClassExpression superCls = ax.getSuperClass();
   607→      return !superCls.getObjectPropertiesInSignature().isEmpty() && (superCls.individualsInSignature()
   608→          .anyMatch(individual -> !EntitySearcher.getObjectPropertyValues(individual, context.getOntology())
   609→              .isEmpty()) || superCls.classesInSignature()
   610→          .anyMatch(cls -> EntitySearcher.getIndividuals(cls, context.getOntology()).findAny().isPresent()));
   611→    }).collect(Collectors.toList());
   612→  }
   613→
   614→  public String getSchemaName() {
   615→    return nameResolver.resolve(cls);
   616→  }
   617→
   618→  private String getSchemaAnnotation(String schema) {
   619→    return '"' + schema + '"' + "^^xsd:string";
   620→  }
   621→
   622→  private String taxonomyName(String taxonomy_name) {
   623→    if (StringUtils.countMatches(taxonomy_name, "_") > 0) {
   624→      return taxonomy_name.substring(taxonomy_name.lastIndexOf("_") + 1);
   625→    }
   626→    return taxonomy_name.substring(0, 1).toUpperCase() + taxonomy_name.substring(1);
   627→  }
   628→
   629→  private String getLabel(final OWLEntity entity) {
   630→    return OntologyUtil.getTitle(entity, context.getOntology());
   631→  }
   632→
   633→  private Stream<OWLSubClassOfAxiom> getSuperClassAxioms(OWLClass analyzedClass,
   634→                                                         @Nullable Set<OWLClass> ignoreClasses) {
   635→    final Set<OWLClass> processedClasses = Optional.ofNullable(ignoreClasses).orElse(new HashSet<OWLClass>());
   636→    final String schemaAnnotation = getSchemaAnnotation(context.getSchemaLabel());
   637→    return context.getOntology().subClassAxiomsForSubClass(analyzedClass)
   638→        .filter(WithAnnotation.of(OntologyConstants.apiLabel, context.getSchemaLabel()))
   639→        .map(OWLSubClassOfAxiom::getSuperClass).filter(OWLClassExpression::isOWLClass).map(AsOWLClass::asOWLClass)
   640→        .filter(Predicate.not(processedClasses::contains)).peek(processedClasses::add) // side effect
   641→        .flatMap(context.getOntology()::subClassAxiomsForSubClass).flatMap(owlSubClassOfAxiom -> {
   642→          final OWLClassExpression superClass = owlSubClassOfAxiom.getSuperClass();
   643→          final List<OWLSubClassOfAxiom> superClassAxioms = new ArrayList<>();
   644→          if (superClass.isOWLClass()) {
   645→            getSuperClassAxioms(superClass.asOWLClass(), processedClasses).forEach(superClassAxioms::add);
   646→          }
   647→          if (owlSubClassOfAxiom.annotations()
   648→              .anyMatch(owlAnnotation -> owlAnnotation.getValue().toString().equals(schemaAnnotation))) {
   649→            superClassAxioms.add(owlSubClassOfAxiom);
   650→          }
   651→          return superClassAxioms.stream();
   652→        });
   653→  }
   654→
   655→}
