| hexBinary | string | - | "48656C6C6F" |
| normalizedString | string | - | |
| token | string | - | |
| language | string | - | "en" |
| NCName | string | - | |
| NMTOKEN | string | - | |
| Name | string | - | |
| QName | string | - | |
| Literal | string | - | |
| langString | string | - | |

##### 3.4.2 Numeric Types (`numeric-types-test.owl`)

