```java
public class TestUtil {
    // Existing methods...

    /**
     * Generate spec and cache by ontology feature name
     */
    public static ReadContext getSpec(String featureName) {
        Path config = Path.of("src/test/resources/regression/configs")
            .resolve(featureName)
            .resolve("config-" + featureName + ".yaml");
        return getGeneratedSpec(config);
    }

    /**
     * Read property schema at path
     */
    public static Map<String, Object> getPropertySchema(ReadContext spec,
        String schemaName, String propertyName) {
        return spec.read(String.format(
            "$.components.schemas.%s.properties.%s", schemaName, propertyName));
    }

    /**
     * Assert schema type and format
     */
    public static void assertSchemaType(ReadContext spec, String schemaName,
        String propertyName, String expectedType, String expectedFormat) {
        String basePath = "$.components.schemas.%s.properties.%s".formatted(
            schemaName, propertyName);
        assertEquals(expectedType, spec.read(basePath + ".type"));
        if (expectedFormat != null) {
            assertEquals(expectedFormat, spec.read(basePath + ".format"));
        }
    }
}
